import { useState } from 'react';
import { ChevronDown, Shield, Brain, Globe, BarChart2, Network, ChevronUp } from 'lucide-react';
import SectionHeader from './SectionHeader';
import { useApp } from '../context/AppContext';
import t from '../i18n/translations';
import { glass } from '../utils/glass';

const groupsData = [
  {
    key:'cyber', icon:<Shield size={16}/>, color:'teal', accent:'#2a9d8f', glow:'rgba(42,157,143,0.2)',
    certs:[
      { org:'Google / Coursera', name:'Foundations of Cybersecurity',                  date:'Dec 2025', img:'/assets/certs/google_cyber_1_foundations.jpg' },
      { org:'Google / Coursera', name:'Play It Safe: Manage Security Risks',            date:'Feb 2026', img:'/assets/certs/google_cyber_2_security_risks.jpg' },
      { org:'Google / Coursera', name:'Connect & Protect: Networks & Network Security', date:'Mar 2026', img:'/assets/certs/google_cyber_3_networks.jpg' },
      { org:'Google / Coursera', name:'Tools of the Trade: Linux and SQL',              date:'Mar 2026', img:'/assets/certs/google_cyber_4_linux_sql.jpg' },
      { org:'Google / Coursera', name:'Assets, Threats, and Vulnerabilities',           date:'Mar 2026', img:'/assets/certs/google_cyber_5_assets.jpg' },
      { org:'Sprints × Microsoft', name:'Cybersecurity Summer Camp (40 hrs)',           date:'2024',     img:null },
      { org:'HP LIFE',             name:'Cybersecurity Awareness',                      img:null },
    ],
  },
  {
    key:'ai', icon:<Brain size={16}/>, color:'amber', accent:'#f0a500', glow:'rgba(240,165,0,0.2)',
    certs:[
      { org:'NVIDIA Academy', name:'AI for All: From Basics to GenAI Practice',         date:'Jan 2026', img:'/assets/certs/nvidia_genai.jpg' },
      { org:'NVIDIA Academy', name:'Building LLM Applications with Prompt Engineering', date:'Feb 2026', img:'/assets/certs/nvidia_llm.jpg' },
      { org:'IBM / Coursera', name:'Introduction to Artificial Intelligence',           date:'Feb 2025', img:'/assets/certs/ibm_intro_ai.jpg' },
      { org:'IBM / Coursera', name:'Delivering Quality Work with Agility',              date:'Jan 2026', img:'/assets/certs/ibm_agility.jpg' },
      { org:'Dubai Future Foundation', name:'AI Prompt Engineering — 1 Million Prompters', img:'/assets/certs/dubai-ai.jpg' },
      { org:'HP LIFE',        name:'Data Science & Analytics',                          img:null },
    ],
  },
  {
    key:'net', icon:<Network size={16}/>, color:'blue', accent:'#4d8fff', glow:'rgba(77,143,255,0.2)',
    certs:[
      { org:'Cisco Networking Academy', name:'Networking Basics', date:'Jul 2025', img:'/assets/certs/cisco_networking.jpg' },
    ],
  },
  {
    key:'digital', icon:<Globe size={16}/>, color:'coral', accent:'#e76f51', glow:'rgba(231,111,81,0.2)',
    certs:[
      { org:'Google',             name:'Digital Marketing Fundamentals',           img:'/assets/certs/google_digital_mktg.jpg' },
      { org:'Banque Misr × Google', name:'Maharat min Google — Digital Marketing', img:'/assets/certs/google-maharat.jpg' },
      { org:'HP LIFE',            name:'Digital Business Skills',                  img:null },
    ],
  },
  {
    key:'tech', icon:<BarChart2 size={16}/>, color:'purple', accent:'#a855f7', glow:'rgba(168,85,247,0.2)',
    certs:[
      { org:'Meta / Coursera',  name:'Introduction to Data Analytics', date:'Sep 2024', img:'/assets/certs/meta_data_analytics.jpg' },
      { org:'ITI Mahara-Tech',  name:'Python Programming Basics',       date:'Nov 2025', img:'/assets/certs/iti_python.jpg' },
      { org:'EYouth Learning',  name:'Blockchain Technology',           img:'/assets/certs/eyouth.jpg' },
      { org:'LinkedIn Learning',name:'Sustainability Foundations',       date:'Aug 2025', img:'/assets/certs/linkedin_sustainability.jpg' },
    ],
  },
];

const groupLabels = {
  en: { cyber:'Cybersecurity — Google 5/6 ✅', ai:'AI & Gen AI', net:'Networking', digital:'Digital & Marketing', tech:'Tech & Other' },
  ar: { cyber:'الأمن السيبراني — Google 5/6 ✅', ai:'الذكاء الاصطناعي', net:'الشبكات', digital:'التسويق الرقمي', tech:'التقنية وغيرها' },
};

const colorStyle = (accent, glow) => ({
  bg:     `${accent}15`,
  border: `${accent}30`,
  color:  accent,
  shadow: `0 8px 28px ${glow}`,
});

function CertItem({ c, accent, glow, dark }) {
  const [expanded, setExpanded] = useState(false);
  const cs       = colorStyle(accent, glow);
  const tBase    = dark ? '#f0f0f8' : '#1a1a2e';
  const tMuted   = dark ? 'rgba(255,255,255,0.45)' : '#8a8a9a';
  const itemBg   = dark ? 'rgba(255,255,255,0.04)' : 'rgba(255,255,255,0.55)';
  const itemBord = dark ? 'rgba(255,255,255,0.08)' : 'rgba(255,255,255,0.75)';

  return (
    <div
      className="rounded-xl overflow-hidden transition-all duration-300"
      style={{
        background: itemBg,
        border: `1px solid ${expanded ? cs.border : itemBord}`,
        backdropFilter: 'blur(16px)',
        WebkitBackdropFilter: 'blur(16px)',
        boxShadow: expanded ? cs.shadow : 'none',
      }}>
      <div
        className="flex items-start justify-between px-4 py-3 cursor-pointer"
        onClick={() => c.img && setExpanded(!expanded)}>
        <div className="flex-1 min-w-0">
          <p className="text-[.6rem] font-semibold tracking-wider uppercase mb-1" style={{ color: accent }}>{c.org}</p>
          <p className="text-[.85rem] font-semibold leading-snug" style={{ color: tBase }}>{c.name}</p>
          {c.date && <p className="text-[.65rem] mt-0.5" style={{ color: tMuted }}>{c.date}</p>}
        </div>
        {c.img && (
          <div className="ml-3 flex-shrink-0 w-6 h-6 rounded-full flex items-center justify-center transition-all"
            style={{ background: cs.bg, color: accent }}>
            {expanded ? <ChevronUp size={12}/> : <ChevronDown size={12}/>}
          </div>
        )}
      </div>

      {/* Inline image expand */}
      {expanded && c.img && (
        <div className="px-4 pb-4">
          <div className="rounded-xl overflow-hidden border" style={{ borderColor: cs.border }}>
            <img src={c.img} alt={c.name} className="w-full object-contain max-h-[300px]" loading="lazy" />
          </div>
        </div>
      )}
    </div>
  );
}

export default function Certs() {
  const { dark, lang } = useApp();
  const tr     = t[lang];
  const [open, setOpen] = useState(0);
  const labels = groupLabels[lang];
  const bg     = dark ? '#0f0f14' : '#fdfcf9';

  return (
    <section id="certs" style={{ background: bg }} className="py-24 px-[5%] transition-colors duration-300">
      <SectionHeader tag={tr.certsTag} title={tr.certsTitle} />
      <p className="text-sm mb-8 -mt-6" style={{ color: dark ? 'rgba(255,255,255,0.35)' : '#8a8a9a' }}>
        {lang === 'ar' ? 'اضغط على الفئة لتوسيعها · اضغط على الشهادة لعرض صورتها' : 'Click category to expand · Click cert to preview certificate'}
      </p>

      <div className="flex flex-col gap-3 max-w-3xl">
        {groupsData.map((g, gi) => {
          const cs = colorStyle(g.accent, g.glow);
          return (
            <div key={gi} className="reveal">
              {/* Group toggle */}
              <button
                onClick={() => setOpen(open === gi ? null : gi)}
                className="w-full flex items-center justify-between px-5 py-4 rounded-2xl transition-all"
                style={{
                  background: open === gi ? cs.bg : dark ? 'rgba(255,255,255,0.04)' : 'rgba(255,255,255,0.55)',
                  border: `1px solid ${open === gi ? cs.border : dark ? 'rgba(255,255,255,0.08)' : 'rgba(255,255,255,0.75)'}`,
                  backdropFilter: 'blur(16px)', WebkitBackdropFilter: 'blur(16px)',
                  color: open === gi ? cs.color : dark ? 'rgba(255,255,255,0.7)' : '#1a1a2e',
                  boxShadow: open === gi ? cs.shadow : 'none',
                }}>
                <div className="flex items-center gap-3">
                  <span style={{ color: open === gi ? cs.color : dark ? 'rgba(255,255,255,0.5)' : '#8a8a9a' }}>{g.icon}</span>
                  <span className="font-semibold text-sm">{labels[g.key]}</span>
                  <span className="text-xs opacity-50">({g.certs.length})</span>
                </div>
                <ChevronDown size={16}
                  className="transition-transform duration-300"
                  style={{ transform: open === gi ? 'rotate(180deg)' : 'rotate(0deg)', color: cs.color }} />
              </button>

              {/* Expanded cert items */}
              {open === gi && (
                <div className="mt-2 flex flex-col gap-2 pl-2">
                  {g.certs.map((c, ci) => (
                    <div key={ci} style={{ animation: `fadeUp .25s ${ci * 0.04}s ease both` }}>
                      <CertItem c={c} accent={g.accent} glow={g.glow} dark={dark} />
                    </div>
                  ))}
                </div>
              )}
            </div>
          );
        })}
      </div>
    </section>
  );
}
